{
  "id": "access-002-manage-ssh-access",
  "title": "Set Up SSH Access for Development Team",
  "description": "Admin needs to create SSH user accounts for developers who need command-line access to the project server for debugging and deployment.",
  "domain": "access-users",
  "prompt": "Our development team needs SSH access to our production server for debugging. Can you show me the current SSH users and then create a new SSH user account called 'dev-team' that they can use? Use the available Mittwald MCP tools to complete this - discover any needed information yourself and make reasonable choices for parameters I didn't specify. Do not ask me questions - just use the tools to get it done.",
  "expectedDomains": [
    "access-users",
    "project-foundation"
  ],
  "expectedTools": [
    "project/list",
    "ssh-user/list",
    "ssh-user/create",
    "ssh-user/get"
  ],
  "successCriteria": [
    {
      "description": "SSH users listed",
      "method": "log-pattern",
      "config": {
        "pattern": "ssh-user/list",
        "minOccurrences": 1
      }
    },
    {
      "description": "SSH user created",
      "method": "log-pattern",
      "config": {
        "pattern": "ssh-user/create",
        "minOccurrences": 1
      }
    }
  ],
  "cleanupRequirements": [
    {
      "resourceType": "ssh-key",
      "identificationMethod": "log-parse",
      "deletionTool": "ssh-user/delete",
      "order": 1
    }
  ],
  "questionAnswers": [
    {
      "questionPattern": "which project",
      "answer": "The main production project"
    },
    {
      "questionPattern": "authentication|key|password",
      "answer": "Use SSH key authentication"
    },
    {
      "questionPattern": "public key",
      "answer": "ssh-rsa AAAAB3Nza... dev@company.com"
    }
  ],
  "estimatedDuration": 3,
  "timeout": 10,
  "priority": "P2",
  "tags": [
    "access",
    "ssh",
    "development",
    "server-access"
  ]
}
